import React, { useState, useEffect } from 'react';
import api from '../../services/api';

const OwnerDashboard = () => {
  const [data, setData] = useState({
    store: null,
    ratings: [],
    averageRating: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchRatings();
  }, []);

  const fetchRatings = async () => {
    try {
      const response = await api.get('/ratings/owner/ratings');
      setData(response.data);
    } catch (error) {
      console.error('Failed to fetch ratings:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="container">Loading dashboard...</div>;
  }

  return (
    <div className="container">
      <h1 style={{ marginBottom: '20px' }}>Store Owner Dashboard</h1>
      
      {data.store && (
        <>
          <div className="card" style={{ marginBottom: '20px' }}>
            <h2>{data.store.name}</h2>
            <p><strong>Address:</strong> {data.store.address}</p>
            <p><strong>Email:</strong> {data.store.email}</p>
            <p><strong>Average Rating:</strong> {parseFloat(data.averageRating).toFixed(2)} ★</p>
            <p><strong>Total Ratings:</strong> {data.ratings.length}</p>
          </div>
          
          <div className="card">
            <h3 style={{ marginBottom: '15px' }}>Users Who Rated Your Store</h3>
            
            {data.ratings.length === 0 ? (
              <p>No ratings yet.</p>
            ) : (
              <div style={{ overflowX: 'auto' }}>
                <table>
                  <thead>
                    <tr>
                      <th>User Name</th>
                      <th>Email</th>
                      <th>Rating</th>
                      <th>Date</th>
                    </tr>
                  </thead>
                  <tbody>
                    {data.ratings.map(rating => (
                      <tr key={rating.id}>
                        <td>{rating.name}</td>
                        <td>{rating.email}</td>
                        <td>{rating.rating} ★</td>
                        <td>{new Date(rating.created_at).toLocaleDateString()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default OwnerDashboard;
